import { WorkflowRuntime } from 'mastra/workflows';

const detectTransitionDrift = (runtime: WorkflowRuntime) => {
  runtime.on('node:output', ({ nodeId, output, nextNodeId }) => {
    const nextNode = runtime.workflow.nodes[nextNodeId];
    if (nextNode?.inputSchema) {
      const { error } = nextNode.inputSchema.safeParse(output);
      if (error) {
        console.error(`Schema drift detected: ${nodeId} -> ${nextNodeId}`, {
          error: error.errors,
          output
        });
      }
    }
  });
};

import { AgentRuntime } from 'mastra/agents';

const validateToolResponses = (agent: AgentRuntime) => {
  agent.interceptToolCalls(async (toolCall) => {
    try {
      const result = await toolCall.execute();
      JSON.parse(result.content);
      return result;
    } catch (e) {
      console.error('Malformed tool response:', toolCall.name, e);
      return {
        ...toolCall,
        content: JSON.stringify({ error: 'malformed_response', raw: result.content })
      };
    }
  });
};

import { MemoryStore } from 'mastra/memory';

const detectStaleContext = (memory: MemoryStore) => {
  memory.on('retrieval', (context) => {
    const now = Date.now();
    const maxAge = 24 * 60 * 60 * 1000; // 24h

    context.entries.forEach(entry => {
      if (now - entry.timestamp > maxAge) {
        console.warn('Stale memory detected:', {
          key: entry.key,
          age: Math.floor((now - entry.timestamp) / (1000 * 60 * 60))
        });
      }
    });
  });
};

