import { z } from 'zod';
import { WorkflowRuntime } from 'mastra/workflows';

const schemaMiddleware = (runtime: WorkflowRuntime) => {
  const schemas: Record<string, z.ZodSchema> = {
    // Define expected schemas per node
    'user-query': z.object({ query: z.string(), intent: z.string().optional() }),
    'tool-executor': z.object({ success: z.boolean(), data: z.record(z.unknown()) })
  };

  runtime.on('node:output', ({ nodeId, output }) => {
    const schema = schemas[nodeId];
    if (schema) {
      const parsed = schema.parse(output);
      runtime.setNodeOutput(nodeId, parsed);
    }
  });
};

import { AgentRuntime } from 'mastra/agents';

const normalizeToolOutputs = (agent: AgentRuntime) => {
  agent.interceptToolCalls(async (toolCall) => {
    const result = await toolCall.execute();

    let normalized;
    try {
      normalized = JSON.parse(result.content);
    } catch {
      // Fallback: extract JSON from text
      const jsonMatch = result.content.match(/\{.+\}/s);
      normalized = jsonMatch ? JSON.parse(jsonMatch[0]) : { raw: result.content };
    }

    return {
      ...result,
      content: JSON.stringify({
        tool: toolCall.name,
        success: true,
        data: normalized,
        timestamp: Date.now()
      })
    };
  });
};

import { MemoryStore } from 'mastra/memory';

const sessionMemoryFilter = (memory: MemoryStore, sessionId: string) => {
  memory.on('retrieval', (context) => {
    context.entries = context.entries.filter(entry => {
      const entryAge = Date.now() - entry.timestamp;
      const isCurrentSession = entry.metadata?.sessionId === sessionId;
      return isCurrentSession && entryAge < 2 * 60 * 60 * 1000; // 2h TTL
    });
  });

  // Auto-expire old entries
  setInterval(() => {
    memory.prune({ maxAge: 24 * 60 * 60 * 1000 });
  }, 60 * 60 * 1000);
};

