import { Vex } from '@vex_dev/sdk';
import { MastraApp } from 'mastra/core';

const app = new MastraApp();
const vex = new Vex({
  projectId: 'your-vex-project',
  apiKey: process.env.VEX_API_KEY!
});

// Vex middleware for Mastra
app.use(async (ctx, next) => {
  // Capture all outputs
  const outputs = [];

  ctx.runtime.on('node:output', (event) => {
    outputs.push({
      nodeId: event.nodeId,
      output: event.output,
      timestamp: Date.now()
    });
  });

  await next();

  // Report to Vex
  await vex.report({
    type: 'mastra-consistency',
    payload: {
      sessionId: ctx.session.id,
      workflowId: ctx.workflow.id,
      outputs,
      toolCalls: ctx.agent?.toolCalls || [],
      memoryHits: ctx.memory?.retrievals || []
    }
  });

  // Vex auto-remediation
  const issues = await vex.analyze('mastra-consistency');
  issues.forEach(issue => {
    if (issue.type === 'schema_drift') {
      ctx.runtime.fixOutput(issue.nodeId, issue.fixedOutput);
    }
  });
});
